<span class="line">    console<span class="token punctuation">.</span><span class="token function">warn</span><span class="token punctuation">(</span><span class="token string">&#39;⚠️ 检测到完整URL，清空baseURL以防止重复拼接&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
